import{_ as e,c as a,o as i,a as o}from"./app.3c34bf24.js";const v=JSON.parse('{"title":"Revisi\xF3n del Sprint","description":"","frontmatter":{},"headers":[{"level":2,"title":"Revisi\xF3n del Incremento","slug":"revision-del-incremento","link":"#revision-del-incremento","children":[]},{"level":2,"title":"Objetivos","slug":"objetivos","link":"#objetivos","children":[]},{"level":2,"title":"Precondiciones","slug":"precondiciones","link":"#precondiciones","children":[]},{"level":2,"title":"Asistentes","slug":"asistentes","link":"#asistentes","children":[]},{"level":2,"title":"Entradas","slug":"entradas","link":"#entradas","children":[]},{"level":2,"title":"Resultados","slug":"resultados","link":"#resultados","children":[]},{"level":2,"title":"Formato de la reuni\xF3n","slug":"formato-de-la-reunion","link":"#formato-de-la-reunion","children":[]},{"level":2,"title":"Protocolo recomendado","slug":"protocolo-recomendado","link":"#protocolo-recomendado","children":[]},{"level":2,"title":"Visi\xF3n general","slug":"vision-general","link":"#vision-general","children":[]}],"relativePath":"events/sprint-review.md"}'),l={name:"events/sprint-review.md"},r=o('<h1 id="revision-del-sprint" tabindex="-1">Revisi\xF3n del Sprint <a class="header-anchor" href="#revision-del-sprint" aria-hidden="true">#</a></h1><blockquote><p>Reuni\xF3n realizada al final del Sprint para comprobar el incremento. No debe durar m\xE1s de 4 horas, en el caso de revisar Sprints largos. Para Sprints de una o dos semanas, con una o dos horas de duraci\xF3n deber\xEDa ser suficiente.</p></blockquote><h2 id="revision-del-incremento" tabindex="-1">Revisi\xF3n del Incremento <a class="header-anchor" href="#revision-del-incremento" aria-hidden="true">#</a></h2><p>Durante la ceremonia de Revisi\xF3n del Incremento, el equipo presentar\xE1 al Due\xF1o del Producto las funcionalidades desarrolladas. Las explicar\xE1 y har\xE1 una demostraci\xF3n de ellas, a fin de que, tanto el Due\xF1o del Producto como la eventual audiencia, puedan experimentarlas.</p><p>El Due\xF1o del Producto podr\xE1 sugerir mejoras a las funcionalidades desarrolladas, aprobarlas por completo o eventualmente, rechazarlas si considera que no se ha cumplido el objetivo.</p><p>La ceremonia de Revisi\xF3n del Incremento se lleva a cabo el \xFAltimo d\xEDa del Sprint, y no tiene una duraci\xF3n fija. En la pr\xE1ctica, se utiliza el tiempo que sea necesario.</p><h2 id="objetivos" tabindex="-1">Objetivos <a class="header-anchor" href="#objetivos" aria-hidden="true">#</a></h2><ul><li>El Due\xF1o del Producto comprueba el progreso del sistema. Esta reuni\xF3n marca, a intervalos regulares, el ritmo de construcci\xF3n, y la trayectoria que va tomando la visi\xF3n del producto.</li><li>El Due\xF1o del Producto identifica las funcionalidades que se pueden considerar \u201Chechas\u201D y las que no.</li><li>Al ver y probar el incremento, el Due\xF1o del Producto, y el equipo en general obtienen retroalimentaci\xF3n relevante para revisar la Pila del Producto.</li><li>Otros ingenieros y programadores de la empresa tambi\xE9n pueden asistir para conocer c\xF3mo trabaja la tecnolog\xEDa empleada.</li></ul><h2 id="precondiciones" tabindex="-1">Precondiciones <a class="header-anchor" href="#precondiciones" aria-hidden="true">#</a></h2><ul><li>Se ha concluido el Sprint.</li></ul><h2 id="asistentes" tabindex="-1">Asistentes <a class="header-anchor" href="#asistentes" aria-hidden="true">#</a></h2><ul><li>Todo el Equipo de Desarrollo.</li><li>El Propietario del Producto.</li><li>El Gestor del Proyecto.</li><li>Todas las personas implicadas en el proyecto que lo deseen.</li></ul><h2 id="entradas" tabindex="-1">Entradas <a class="header-anchor" href="#entradas" aria-hidden="true">#</a></h2><ul><li>Incremento terminado.</li></ul><h2 id="resultados" tabindex="-1">Resultados <a class="header-anchor" href="#resultados" aria-hidden="true">#</a></h2><ul><li>Retroalimentaci\xF3n para el Due\xF1o del Producto: hito de seguimiento de la construcci\xF3n del sistema, e informaci\xF3n para mejorar el valor de la visi\xF3n del producto.</li><li>Convocatoria de la Reuni\xF3n de Planificaci\xF3n del siguiente Sprint.</li></ul><h2 id="formato-de-la-reunion" tabindex="-1">Formato de la reuni\xF3n <a class="header-anchor" href="#formato-de-la-reunion" aria-hidden="true">#</a></h2><ul><li>Es una reuni\xF3n informal e informativa. El objetivo es ver el incremento realizado. Su misi\xF3n no es la toma de decisiones ni la cr\xEDtica del incremento.</li><li>Est\xE1n prohibidas las presentaciones gr\xE1ficas. Pero seg\xFAn las caracter\xEDsticas del proyecto puede incluir tambi\xE9n documentaci\xF3n de usuario, o t\xE9cnica.</li><li>El equipo no debe invertir m\xE1s de una hora en desarrollar la reuni\xF3n, y lo que se muestra es el resultado final: terminado, probado y operando en el entorno del usuario (incremento).</li><li>Con la informaci\xF3n obtenida, posteriormente el Due\xF1o del Producto tratar\xE1 las posibles modificaciones sobre la visi\xF3n del producto.</li></ul><h2 id="protocolo-recomendado" tabindex="-1">Protocolo recomendado <a class="header-anchor" href="#protocolo-recomendado" aria-hidden="true">#</a></h2><ul><li>El equipo expone el objetivo del Sprint, la lista de funcionalidades que se inclu\xEDan y las que se han desarrollado.</li><li>El equipo hace una introducci\xF3n general del Sprint y demuestra el funcionamiento de las partes construidas.</li><li>Se abre un turno de preguntas y sugerencias. Esta parte genera informaci\xF3n valiosa para que el Due\xF1o del Producto y el equipo en general, puedan mejorar la visi\xF3n del producto.</li><li>El Gestor del Proyecto, de acuerdo con las agendas del Due\xF1o del Producto y el Equipo de Desarrollo, cierra la fecha para la reuni\xF3n de preparaci\xF3n del siguiente Sprint.</li></ul><h2 id="vision-general" tabindex="-1">Visi\xF3n general <a class="header-anchor" href="#vision-general" aria-hidden="true">#</a></h2><p><strong>Objetivos</strong></p><ul><li>Que los principales interesados experimenten las funcionalidades construidas y eventualmente sugieran alguna mejora.</li><li>Que el Due\xF1o del Producto acepte o rechace las funcionalidades construidas.</li></ul><p><strong>Participantes</strong></p><ul><li>Gestor del Proyecto.</li><li>Due\xF1o del Producto.</li><li>Equipo de Desarrollo .</li><li>Audiencia (opcionalmente).</li></ul><p><strong>Momento</strong></p><ul><li>Despu\xE9s del \xFAltimo d\xEDa del Sprint.</li></ul><p><strong>Duraci\xF3n</strong></p><ul><li>No menor a 1 hora y no mayor una jornada completa.</li></ul><p><strong>Artefactos involucrados</strong></p><ul><li>El Incremento de funcionalidades.</li></ul><p><strong>Din\xE1mica</strong></p><ul><li>El Equipo de Desarrollo presenta los items desarrollados de la Pila del Sprint y procede a mostrar el software en funcionamiento</li><li>El Due\xF1o del Producto y principales interesados realizan al Equipo de Desarrollo consultas referidas al funcionamiento y eventualmente, el Due\xF1o del Producto, podr\xE1 sugerir mejoras o solicitar la implementaci\xF3n de las mismas en el entorno de producci\xF3n.</li><li>Actualizaci\xF3n de la Pila del Producto (opcional). Aquellas funcionalidades a\xFAn no resueltas (y planificadas), el Due\xF1o del Producto, las reincorpora a la Pila del Producto.</li></ul>',33),n=[r];function s(d,t,c,u,p,m){return i(),a("div",null,n)}const f=e(l,[["render",s]]);export{v as __pageData,f as default};
